const key = (x: number, y: number) => `${x},${y}`;
const parseKey = (k: string): Cell => {
  const [xs, ys] = k.split(",");
  return [Number(xs), Number(ys)];
};

const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
  isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3;

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }
  const next: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    if (livesNextGeneration(alive.has(k), count)) {
      next.push(parseKey(k));
    }
  }
  return next;
}
